import { useState, useEffect, useRef } from "react";

const G = "#C9A84C", G2 = "#E8C96A";
const IMG = {
  merrill:  "data:image/webp;base64,",
  fidelity: "data:image/webp;base64,",
  finwell:  "data:image/webp;base64,",
  crowd:    "data:image/webp;base64,",
  tipseelogo: "data:image/webp;base64,",
  dallas:    "data:image/webp;base64,",
  stadium:    "data:image/webp;base64,",
  hero:     "data:image/webp;base64,",
  plane:    "data:image/webp;base64,",
  rodeo:    "data:image/webp;base64,",
};

function useCountUp(target, duration, active) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!active) { setVal(0); return; }
    let s = null, r;
    const tick = ts => { if (!s) s = ts; const p = Math.min((ts-s)/duration,1); setVal(Math.round(target*(1-Math.pow(1-p,3)))); if(p<1) r=requestAnimationFrame(tick); };
    r = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(r);
  }, [active, target, duration]);
  return val;
}

function useSmall() {
  const chk = () => window.innerWidth < 1024 || window.innerHeight < 620;
  const [v, set] = useState(chk);
  useEffect(() => {
    const fn = () => set(chk());
    window.addEventListener("resize", fn);
    window.addEventListener("orientationchange", fn);
    return () => { window.removeEventListener("resize", fn); window.removeEventListener("orientationchange", fn); };
  }, []);
  return v;
}

const CT = { position:"absolute", top:0, left:0, right:0, height:2, background:`linear-gradient(90deg,${G},${G2},transparent)` };

function Card({ children, style }) {
  return <div style={{ background:"rgba(17,17,17,0.95)", border:"1px solid rgba(201,168,76,0.25)", padding:18, position:"relative", ...style }}><div style={CT}/>{children}</div>;
}
function Lbl({ c }) { return <div style={{ fontFamily:"monospace", fontSize:10, letterSpacing:"0.18em", textTransform:"uppercase", color:G, opacity:0.8, marginBottom:8 }}>{c}</div>; }
function Rule() { return <div style={{ width:50, height:2, background:`linear-gradient(90deg,${G},transparent)`, margin:"10px 0 0" }}/>; }
function Badge({ children }) { return <span style={{ fontFamily:"monospace", fontSize:9, letterSpacing:"0.08em", border:"1px solid rgba(201,168,76,0.3)", padding:"4px 9px", color:G, textTransform:"uppercase", background:"rgba(201,168,76,0.07)", whiteSpace:"nowrap" }}>{children}</span>; }
function Pill({ children }) { return <span style={{ fontSize:11, color:"#F5F2EC", background:"#1a1a1a", border:"1px solid rgba(201,168,76,0.18)", padding:"5px 11px", whiteSpace:"nowrap" }}>{children}</span>; }
function H({ children, sz }) { return <div style={{ fontFamily:"Georgia,serif", fontSize:sz||"clamp(26px,4.5vw,50px)", fontWeight:700, lineHeight:1.05, letterSpacing:"-0.02em", color:"#F5F2EC" }}>{children}</div>; }
function Bar() { return <div style={{ position:"absolute", left:0, top:0, bottom:0, width:4, background:`linear-gradient(180deg,${G},${G2} 50%,transparent)`, zIndex:10 }}/>; }

function Wrap({ active, children, style }) {
  return (
    <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", opacity:active?1:0, transform:active?"translateY(0)":"translateY(22px)", transition:"opacity 0.5s ease,transform 0.5s ease", pointerEvents:active?"all":"none", background:"#080808", overflowY:"auto", overflowX:"hidden", WebkitOverflowScrolling:"touch", ...style }}>
      <Bar/>
      {children}
    </div>
  );
}

function BgFixed({ src, active, opacity=0.82, pos="center 40%" }) {
  return (
    <div style={{ position:"fixed", inset:0, zIndex:0, opacity:active?1:0, transition:"opacity 0.5s ease", pointerEvents:"none" }}>
      <img src={src} alt="" style={{ width:"100%", height:"100%", objectFit:"cover", objectPosition:pos }}/>
      <div style={{ position:"absolute", inset:0, background:`rgba(4,4,4,${opacity})` }}/>
      <div style={{ position:"absolute", bottom:0, left:0, right:0, height:"28%", background:"linear-gradient(to top,#080808,transparent)" }}/>
      <div style={{ position:"absolute", top:0, left:0, right:0, height:"14%", background:"linear-gradient(to bottom,#080808,transparent)" }}/>
    </div>
  );
}

