/* ── APP ─────────────────────────────────────────── */
const SLIDES = [S1, S2, S3, S4, S5, S6, S7];

export default function App() {
  const [cur, setCur] = useState(0);
  const [busy, setBusy] = useState(false);
  const sm = useSmall();
  const n = SLIDES.length;
  const tx = useRef(0);

  function go(idx) {
    if (busy || idx === cur || idx < 0 || idx >= n) return;
    setBusy(true);
    setTimeout(() => { setCur(idx); setBusy(false); }, 30);
  }

  useEffect(() => {
    const fn = e => {
      if (e.key === "ArrowRight" || e.key === "ArrowDown") go(cur + 1);
      if (e.key === "ArrowLeft"  || e.key === "ArrowUp")   go(cur - 1);
    };
    window.addEventListener("keydown", fn);
    return () => window.removeEventListener("keydown", fn);
  }, [cur, busy]);

  return (
    <div
      style={{ background:"#080808", color:"#F5F2EC", fontFamily:"'Segoe UI',system-ui,sans-serif", height:"100vh", width:"100%", overflow:"hidden", position:"relative" }}
      onTouchStart={e => { tx.current = e.touches[0].clientX; }}
      onTouchEnd={e => { const dx = e.changedTouches[0].clientX - tx.current; if (Math.abs(dx) > 50) go(dx < 0 ? cur+1 : cur-1); }}
    >
      <div style={{ position:"absolute", inset:0 }}>
        {SLIDES.map((Comp, i) => <Comp key={i} active={i === cur}/>)}
      </div>

      <div style={{ position:"fixed", top:14, right:18, zIndex:200, fontFamily:"monospace", fontSize:11, color:"#888", background:"rgba(8,8,8,0.7)", padding:"3px 8px", backdropFilter:"blur(4px)" }}>
        <span style={{ color:G }}>{cur+1}</span> / {n}
      </div>

      <div style={{ position:"fixed", bottom: sm?14:20, right: sm?14:24, zIndex:200, display:"flex", alignItems:"center", gap:10 }}>
        <div style={{ display:"flex", gap:6, alignItems:"center" }}>
          {Array.from({ length:n }).map((_,i) => (
            <div key={i} onClick={() => go(i)} style={{ width:i===cur?18:6, height:6, borderRadius:i===cur?3:"50%", background:i===cur?G:"rgba(201,168,76,0.3)", cursor:"pointer", transition:"all 0.3s" }}/>
          ))}
        </div>
        {[["←",cur-1],["→",cur+1]].map(([label,idx]) => (
          <button key={label} onClick={() => go(idx)} disabled={idx<0||idx>=n}
            style={{ width: sm?44:38, height: sm?44:38, border:"1px solid rgba(201,168,76,0.3)", background:"rgba(8,8,8,0.9)", color:G, fontSize:16, cursor:idx<0||idx>=n?"default":"pointer", display:"flex", alignItems:"center", justifyContent:"center", opacity:idx<0||idx>=n?0.2:1, transition:"all 0.2s", backdropFilter:"blur(6px)" }}>
            {label}
          </button>
        ))}
      </div>
    </div>
  );
}
